<template>
  <aside class="aside-container" :style="'top:'+scrollY+'px'">
    <div class="side-bar-content">
      <a href="javascript:;" class="aside-item" @click='scrollTo(item.code)' :name='item.code' v-for="item in sideBarList" :key="item.code">{{item.name}}</a>
      <a href="javascript:;" class="side-bar-controler">
        <i class="blbl-icon side-bar-icon customize"></i>
      </a>
      <a href="javascript:;" class="side-bar-controler">
        <i class="blbl-icon side-bar-icon go-top"></i>
      </a>
    </div>
    <div class="side-bar-download">
      <a href="javascript:;">
        <div
          class="side-bar-download-animation"
          @mouseover="downloadAnimation"
          @mouseout="clearAnimation"
          :style="'background-position-x:'+bg_x+'px'"
        ></div>
        <transition name="side-bar-downlaod">
          <div v-show="showSideTips" class="side-bar-download-tips"></div>
        </transition>
      </a>
    </div>
  </aside>
</template>
<script>
import { setInterval, clearInterval } from "timers";
import { constants } from 'crypto';
export default {
  props:{
    position:{
      type:Object,
      default(){
        return {}
      }
    }
  },
  data() {
    return {
      showSideTips: false,
      ani_timer: null,
      bg_dx: 80,
      bg_x: 0,
      scrollY: 230,
      sideBarList: [
        {
          name:"直播",
          code:'live'
        },
        {
          name:"动画",
          code:'cartoon'
        },
        {
          name:"番剧",
          code:'fanju'
        },
        {
          name:"国创",
          code:'guochan'
        },
        {
          name:"漫画",
          code:''
        },
        {
          name:"音乐",
          code:'music'
        },
        {
          name:"舞蹈",
          code:'dance'
        },
        {
          name:"游戏",
          code:'game'
        },
        {
          name:"科技",
          code:'science'
        },
        {
          name:"数码",
          code:'digital'
        },
        {
          name:"生活",
          code:'life'
        },
        {
          name:"鬼畜",
          code:'guichu'
        },
        {
          name:"时尚",
          code:'fashion'
        },
        {
          name:"广告",
          code:'ad'
        },
        {
          name:"娱乐",
          code:'entertainment'
        },
        {
          name:"专栏",
          code:'speacial-column'
        },
        {
          name:"电影",
          code:'movie'
        },
        {
          name:"TV剧",
          code:'tv'
        },
        {
          name:"影视",
          code:'movies'
        },
        {
          name:"纪录片",
          code:'documentary'
        }
      ],
      activeSection:[]
    };
  },
  methods: {
    downloadAnimation() {
      this.showSideTips = true;
      if (this.ani_timer) clearInterval(this.ani_timer);
      this.ani_timer = setInterval(() => {
        if (this.bg_x <= -1200 && this.bg_dx > 0) this.bg_dx = -1 * this.bg_dx;
        if (this.bg_x >= -720 && this.bg_dx < 0) this.bg_dx = -1 * this.bg_dx;
        this.bg_x -= this.bg_dx;
      }, 100);
    },
    clearAnimation() {
      this.showSideTips = false;
      if (this.ani_timer) clearInterval(this.ani_timer);
      this.ani_timer = setInterval(() => {
        this.bg_x += 80;
        if (this.bg_x == 0) {
          clearInterval(this.ani_timer);
          this.bg_dx = 80;
        }
      }, 100);
    },
    scrollTo(code){
      window.scrollTo({
        top:this.position[code] + 220,
        behavior: "smooth" 
      })
    }
  },
  created(){
    console.log('created')
    var position = this.position
    
    // console.log(this.activeSection)
  },
  mounted() {
    var H = window.innerHeight;
    var x = (H - 634) / 2;
    var offsetY = x < 0 ? 0 : x;
    window.onresize = () => {
      H = window.innerHeight;
			x = (H - 634) / 2;
			offsetY = x < 0 ? 0 : x;
    };
    window.onscroll = () => {
      let wsy = window.scrollY
      this.scrollY = wsy >= 230 ? offsetY : 230;
    };



  }
};
</script>
<style scoped>
/* 动画 */
.side-bar-downlaod-enter,
.side-bar-downlaod-leave-to {
  opacity: 0;
}
.side-bar-downlaod-enter-active,
.side-bar-downlaod-leave-active {
  transition: all 0.5s ease;
}

.aside-container {
  position: fixed;
  top: 230px;
  transform: translateX(120%);
  width: auto;
  transition: all 0.3s ease;
}
.side-bar-content {
  padding-top: 6px;
  background-color: #f6f9fa;
  border: 1px solid #e5e9ef;
  border-radius: 4px;
  overflow: hidden;
}
.aside-item {
  display: block;
  text-decoration: none;
  color: #222;
  width: 48px;
  height: 24px;
  line-height: 24px;
  text-align: center;
  transition: all 0.3s ease;
}
.aside-item-checked {
  background-color: #00a1d6;
  color: #fff;
}
.side-bar-controler {
  display: block;
  height: 16px;
  padding: 8px 0;
  border-top: 1px solid #e5e9ef;
  transition: all 0.3s ease;
}
.aside-item:hover,
.side-bar-controler:hover {
  background-color: #00a1d6;
  color: #fff;
}
.side-bar-icon {
  display: block;
  height: 18px;
  width: 18px;
  margin: 0 auto;
  transform: scale(0.7);
}
.customize {
  background-position: -663px -151px;
}
.go-top {
  background-position: -663px -89px;
}
.side-bar-controler:hover .customize {
  background-position: -727px -151px;
}
.side-bar-controler:hover .go-top {
  background-position: -727px -89px;
}
.side-bar-download {
  position: relative;
  width: 50px;
}
.side-bar-download-animation {
  position: relative;
  left: 15px;
  width: 80px;
  height: 80px;
  background: url(https://s1.hdslb.com/bfs/static/jinkela/home/asserts/app-download.png)
    no-repeat;
}
.side-bar-download-tips {
  position: absolute;
  left: -110px;
  top: -20px;
  width: 106px;
  height: 44px;
  background-image: url(https://s1.hdslb.com/bfs/static/jinkela/home/asserts/app-download-tips.png);
}
</style>
